#define BLOCK_SIZE 16
#define WIDTH 16
#define HEIGHT 16
#define ETA 0.3f
#define MOMENTUM 0.3f

float squash(float x)
{
    return (1.0f / (1.0f + exp(-x)));
}

kernel void bpnn_layerforward_ocl(
    global float *l1,
    global float *l2,
    global float *conn,
    global float *partial_sum,
    local float *local_sum,
    local float *local_conn,
    int n1,
    int n2)
{
    int j = get_global_id(1);
    int block_id = get_global_id(0) / BLOCK_SIZE;
    int local_id = get_local_id(0);

    if (j >= 1 && j <= n2) {
        float sum = 0.0f;

        int k_start = block_id * BLOCK_SIZE;
        int k_end = min(k_start + BLOCK_SIZE, n1 + 1);

        for (int k = k_start; k < k_end; k++) {
            sum += conn[k * (n2 + 1) + j] * l1[k];
        }

        partial_sum[block_id * n2 + (j - 1)] = sum;
    }
}

kernel void bpnn_adjust_weights_ocl(
    global float *delta,
    int ndelta,
    global float *ly,
    int nly,
    global float *w,
    global float *oldw)
{
    int j = get_global_id(1);
    int k = get_global_id(0);

    if (j >= 1 && j <= ndelta && k >= 0 && k <= nly) {
        float new_dw = (ETA * delta[j] * ly[k]) + (MOMENTUM * oldw[k * (ndelta + 1) + j]);
        w[k * (ndelta + 1) + j] += new_dw;
        oldw[k * (ndelta + 1) + j] = new_dw;
    }
}
